-- Values self-pad to 8: they concatenate inside record bodies.
encodeValue :: Value -> Builder
encodeValue v = case v of
  VBool x -> word32LE valueBool <> word32LE 1 <> word8 (if x then 1 else 0)
    <> byteString (BS.replicate 7 0)
  VI64 x -> word32LE valueI64 <> word32LE 8 <> int64LE x
  VF64 x -> word32LE valueF64 <> word32LE 8 <> word64LE (castDoubleToWord64 x)
  VStr x ->
    let utf8 = BL.toStrict (toLazyByteString (stringUtf8 x))
        n = BS.length utf8
        padded = (n + 7) .&. complement 7
     in word32LE valueStr <> word32LE (fromIntegral n) <> byteString utf8
          <> byteString (BS.replicate (padded - n) 0)
  VBlob x -> word32LE valueBlob <> word32LE 8 <> word64LE x

-- A key path: {u32 count, u32 reserved, count values}.
-- | A counted value sequence: a key path or a record.
encodeValues :: [Value] -> Builder
encodeValues vals =
  word32LE (fromIntegral (length vals)) <> word32LE 0 <> foldMap encodeValue vals

-- | A collection's element sum: per variant, counted value-type tags,
-- padded to 8. A record collection is the one-variant case.
encodeVariantSchemas :: [[Word32]] -> Builder
encodeVariantSchemas variants =
  let one schema = word32LE (fromIntegral (length schema)) <> foldMap word32LE schema
      body = word32LE (fromIntegral (length variants)) <> word32LE 0 <> foldMap one variants
      len = 8 + 4 * (length variants + sum (map length variants))
      padding = (8 - len `mod` 8) `mod` 8
   in body <> byteString (BS.replicate padding 0)

wireRecord :: Word16 -> Builder -> Builder
wireRecord kind body =
  let bytes = BL.toStrict (toLazyByteString body)
      size = 8 + BS.length bytes
      padded = (size + 7) .&. complement 7
   in word32LE (fromIntegral padded) <> word16LE kind <> word16LE 0
        <> byteString bytes <> byteString (BS.replicate (padded - size) 0)

